const items = $input.all().map(i => i.json);
if (!items || items.length === 0) return [];

const heitor = items.filter(i => i.responsavel === 'Heitor');
const lara = items.filter(i => i.responsavel === 'Lara');

function formatarAlerta(msgs, titulo) {
  if (msgs.length === 0) return null;
  const agora = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });
  const porMentorado = {};
  for (const m of msgs) {
    if (!porMentorado[m.mentorado_nome]) porMentorado[m.mentorado_nome] = [];
    porMentorado[m.mentorado_nome].push(m);
  }
  const linhas = [
    `*${titulo}*`,
    `_${agora}_`,
    ``,
    `*${msgs.length} msg | ${Object.keys(porMentorado).length} mentorado(s)*`,
  ];
  const criticos = msgs.filter(i => i.tier === 5).length;
  const urgentes = msgs.filter(i => i.tier === 4).length;
  const atencao = msgs.filter(i => i.tier === 3).length;
  if (criticos > 0) linhas.push(`Critico (>24h): ${criticos}`);
  if (urgentes > 0) linhas.push(`Urgente (>12h): ${urgentes}`);
  if (atencao > 0) linhas.push(`Atencao (>8h): ${atencao}`);
  linhas.push(``, `${'---'.repeat(9)}`);
  for (const [nome, ms] of Object.entries(porMentorado)) {
    linhas.push(``, `*${nome}* - ${ms.length} pendente(s)`);
    for (const msg of ms.slice(0, 3)) {
      const mins = msg.minutos_pendente || 0;
      const tempo = mins >= 60 ? `${Math.floor(mins/60)}h${mins%60>0?mins%60+'min':''}` : `${mins}min`;
      const preview = (msg.conteudo || '').substring(0, 100);
      linhas.push(`  [${tempo}] ${msg.sender_name}: _${preview}_`);
    }
    if (ms.length > 3) linhas.push(`  _...e mais ${ms.length - 3}_`);
  }
  linhas.push(``, `_Responda o quanto antes._`);
  return linhas.join('\n');
}

const msgHeitor = formatarAlerta(heitor, 'PENDENTES - SUA CARTEIRA');
const msgLara = formatarAlerta(lara, 'PENDENTES - SUA CARTEIRA');
const msgGeral = formatarAlerta(items, 'MENSAGENS SEM RESPOSTA');

return [{ json: {
  msg_heitor: msgHeitor,
  msg_lara: msgLara,
  msg_geral: msgGeral,
  total_heitor: heitor.length,
  total_lara: lara.length,
  total_geral: items.length
}}];
